根据图解给出Prim算法的实现过程代码如下：
void Prim(Graph G, int v){
    int k, lowcost[MAX_VEX], closevertex[MAX_VEX];
    for(int i = 0; i &lt; G.numvex; i++){
        lowcost[i] = G.arc[v][i];            //初始化 将第v行的权值依次纳入其中，含义就是v到其他顶点的权值
        closevertex[i] = v;                //保存相邻结点的信息，可以理解为下一个构成最小生成树结点的前驱
    }
    for(int i = 0; i &lt; G.numvex; i++){
        int min = INF;
        for(int j = 0 ;j &lt; G.numvex; j++ ){
            if(lowcost[j] &lt; min &amp;&amp; lowcost[j] != 0){
                min = lowcost[j];             // 不断更新最小值，直到它是当前的最小值 
                k = j;                              // 将找到的最小权值的下标赋值给k
            }
        }
        printf(&quot;arc from V%d to V%d wight : %d\n&quot;, closevertex[k], k, lowcost[k]);
        lowcost[k] = 0;                    //当前顶点的权值设置为0，表示此顶点已经找到最小生成树的顶点，进行下一个顶点的查找
        for(int j = 0; j &lt; G.numvex; j++){
            if(lowcost[j] != 0 &amp;&amp; lowcost[j] &gt; G.arc[k][j]){         //如果当前v到目标点的路径 有比刚刚最小值点到目标点大的话，修正最小值
                lowcost[j] = G.arc[k][j];
                closevertex[j] = k;                     // 找到与构成最小生成树顶点相邻的顶点信息，其实也就是前驱的顶点
            }
        }
        cout &lt;&lt; endl;
    }
}
完整版实现过程代码如下：
#include &lt;iostream&gt;
#include &lt;cstdio&gt;
#define MAX_VEX 100
#define INF 65535
using namespace std;
struct Graph{
    char vexs[MAX_VEX];
    int arc[MAX_VEX][MAX_VEX];
    int numvex,numarc;
};
void CreateGraph(Graph &amp;G){
    int vi, vj, w;
    cout &lt;&lt; &quot;please enter the number of vertexes and arcs : \n&quot;;
    cin &gt;&gt; G.numvex &gt;&gt; G.numarc;
    for(int i = 0; i &lt; G.numvex; i++){
        printf(&quot;Please enter the NO.%d name of vex : &quot;,i+1);
        cin &gt;&gt; G.vexs[i];
    }

    for(int i = 0; i &lt; G.numvex; i++){
        for(int j = 0; j &lt; G.numvex ;j++){
            G.arc[i][j] = INF;
        }
    }
    cout &lt;&lt; endl;
    for(int i = 0; i &lt; G.numarc; i++){
        cout&lt;&lt; &quot;Enter the subscripts and weights from vertex vi to vertex vj : &quot;;
        cin &gt;&gt; vi &gt;&gt; vj &gt;&gt; w;
        G.arc[vi][vj] = w;
        G.arc[vj][vi] = w;
    }
}
void DispalyGraph(Graph G){
    for(int i = 0; i &lt; G.numvex; i++) cout &lt;&lt; G.vexs[i] &lt;&lt; &quot; &quot;;
    cout &lt;&lt; endl;
    for(int i = 0; i &lt; G.numvex; i++){
        for(int j = 0; j &lt; G.numvex; j++){
            if(G.arc[i][j] == INF) printf(&quot;%6s&quot;, &quot;∞&quot;);
            else printf(&quot;%6d&quot;, G.arc[i][j]);
        }
        cout &lt;&lt; endl;
    }
}
void Prim(Graph G, int v){
    int k, lowcost[MAX_VEX], closevertex[MAX_VEX];
    for(int i = 0; i &lt; G.numvex; i++){
        lowcost[i] = G.arc[v][i];
        closevertex[i] = v;
    }
    for(int i = 0; i &lt; G.numvex; i++){
        int min = INF;
        for(int j = 0 ;j &lt; G.numvex; j++ ){
            if(lowcost[j] &lt; min &amp;&amp; lowcost[j] != 0){
                min = lowcost[j];
                k = j;
            }
        }
        printf(&quot;arc from V%d to V%d wight : %d\n&quot;, closevertex[k], k, lowcost[k]);
        lowcost[k] = 0;
        for(int j = 0; j &lt; G.numvex; j++){
            if(lowcost[j] != 0 &amp;&amp; lowcost[j] &gt; G.arc[k][j]){
                lowcost[j] = G.arc[k][j];
                closevertex[j] = k;
            }
        }
        cout &lt;&lt; endl;
    }
    for(int i = 0; i &lt; G.numvex; i++) cout &lt;&lt; closevertex[i]&lt;&lt; &quot; &quot;;
}
int main(){
    Graph G;
    CreateGraph(G);
    DispalyGraph(G);
    Prim(G,0);
    return 0;
}
    /*
    0 1 6
    0 2 1
    0 3 5
    1 2 5
    2 3 5
    1 4 3
    4 2 6
    2 5 4
    5 3 2
    4 5 6*/
实现结果解释：

观察执行的过程，比较容易理解 这里每一行输出的信息，依次为 closevertex[k], k, lowcost[k]。含义就是 从V0-v2 构成的边的权值为，第二次是V2-v0，这样正好和第二次探索的数组 1 5 0 5 6 4 符合，将lowcost[0]置为0 得到 0 5 0 5 6 4  由于并没有比当前lowcost 中权值小的，所以当前lowcost 数组值不做任何变化。继续探索 过程就是 V2-V5 权值为 4 ，V5-V3 权值为2， V2-v1 权值为5， V1-V4 权值为3 。这样就构成了最小生成树。通过closevertex 来去保存k的值，k就是此次找到构成最小最小生成树的顶点，而输出时的closevertex 输出的是上一次保存k的值。所以这就是说closevertex是保存当前构成最小生成树的前驱结点啦~ 理解这个很重要，它类似与最短路径 Dijkstra算法十分相似，他们的思想本质也是一样的，用一个数组来保存前驱，区别就是加上判断条件完成找到时不改变信息，完成构建时就是最短路径的下标，这个在Dijkstra算法中详细说到。

通过C++中的引用建立链表  
通过C++中的引用建立链表
通过C++引用语法实现对链表的改动void change( int &amp;a, int &amp;b)change(a,b);int &amp;a 相当于a的别名，er int &amp;a  是双向的可用的在C语言我改变元&gt;素的值通常使用指针改变函数的值，通过传递其地址    

代码如下：
#include &lt;iostream&gt;
#include&lt;cstdio&gt;
#include&lt;stdlib.h&gt;
typedef struct node{
    int data;
    struct node *next;
}link,*linkednode;
// 在此使用头插法完成链表的建立
void CreateLink(linkednode &amp;L)
{
    linkednode s;
    L=(linkednode)malloc(sizeof(link));
    L-&gt;next=NULL;
    for(int i=0;i&lt;10;i++)
    {
        s=(linkednode)malloc(sizeof(link));
        s-&gt;data=i;
        // 插入结点信息
        s-&gt;next=L-&gt;next;
        L-&gt;next=s;
    }
}
// 输出结点信息
void printLinkinfo(linkednode &amp;L)
{
    linkednode temp;
    temp =(linkednode)malloc(sizeof(link));
    temp=L;
    while(temp-&gt;next)
    {
        printf(&quot;%d&quot;,temp-&gt;data);
        temp=temp-&gt;next;
    }
}
// 使用尾插法建立链表的操作
void CreateLink2(linkednode &amp;L)
{
    linkednode s,t;
    L=(linkednode)malloc(sizeof(link));
    L-&gt;next=NULL;
    t=L;
    int i;
    for( i=0;i&lt;10;i++)
    {
        s=(linkednode)malloc(sizeof(link));
        s-&gt;data=i;
        s-&gt;next=NULL;
        t-&gt;next=s;
        t=s;
    }
}

// 删除结点信息
void deleteinfo(linkednode &amp;L,int i)
{
    linkednode temp ,t;
    int j=0;
    temp=(linkednode)malloc(sizeof(link));
    temp=L;
    while(temp-&gt;next&amp;&amp;(j&lt;i-1))
   {
       temp =temp-&gt;next;
       j++;
   }
    t=temp-&gt;next;
    temp-&gt;next=t-&gt;next;
    printf(&quot;删除的数据为%d&quot;,t-&gt;data);
}
void insertinfo(linkednode &amp;L,int loc,int e)
{
    int j=0;
    linkednode temp,s;
    temp=L;
    while(temp-&gt;next&amp;&amp;j&lt;(loc-1))
    {
        temp=temp-&gt;next;
        j++;
    }
    s=(linkednode)malloc(sizeof(link));
    s-&gt;data=e;
    s-&gt;next=temp-&gt;next;
    temp-&gt;next=s;
}
int main()
{
    link *L=NULL;
    // 头插法
    //CreateLink(L);
    //尾插法
    CreateLink2(L);
    // 输出信息
    printLinkinfo(L);
    printf(&quot;\n&quot;);
    deleteinfo(L,3);
    printf(&quot;\n&quot;);
    printLinkinfo(L);
    printf(&quot;\n&quot;);
    insertinfo(L,3,6);
    printLinkinfo(L);
    return 0;
}

ecplise中创建Dynamic web project时版本不同注册sevlet信息的差异  
ecplise中创建Dynamic web project时版本不同注册sevlet信息的差异 我在ecplise一直使用的web工程是2.5版本的 最近在创建新版本web工程时发现了一点不同——web工程版本不同注册sevlet方式不同
2.5及之前版本
   如果通过类实现Serlvet的方法来使用serlvet时 需要在web.xml文件中注册servlet信息 如下图 ：


在web.xml文件中注册的信息为：



过程如下 
通过tomcat找到项目名称
在web.xml文件中找到url-pattern代表搜索时的输入的内容，在这里内容为/prac
通过servlet-mapping找到servlet-name为parc
由此找到上面的servlet中的servlet-name
之后找到代表路径通过servlet-class
执行类中方法结果如下：




注意：在XML中对servlet信息的注册过程中servlet 和 servlet mapping 中的 servlet-name需要保持保持一致但是可为任意，而url-pattern 的内容也可以任意，但是搜索时需要更改对应url内容 如url-pattern 的内容/a 搜索的url为localhost:8080/PracPreviousVersion/a


通过类继承HttpServlet时注册servlet信息原理一致，继承HttpServlet就类似于Adaptor 的设计模式
当然一般来说直接写servlet文件就可以，此时在web.xml文件时自动就会注册servlet文件信息




如果是3.0版本即以上
创建servlet文件时通过注释来注册信息，在默认情况在webcontent中隐藏了web.xml文件



通过自动创建servlet文件自动生成注册信息



如果实现servlet时需要添加注释信息通过@WebServlet(“/ServletDemo02”) 代表url-pattern 同理 url-pattern 的内容可以更改 对应url查找也需要该改，使用注释的方式也可以添加initParam 或者特定urlpattern  代码如下：
package ServletDemo;

import java.io.IOException;

import javax.servlet.Servlet;
import javax.servlet.ServletConfig;
import javax.servlet.ServletException;
import javax.servlet.ServletRequest;
import javax.servlet.ServletResponse;
import javax.servlet.annotation.WebInitParam;
import javax.servlet.annotation.WebServlet;

@WebServlet(name=&quot;/ServletDemo02&quot;,urlPatterns= {&quot;/aa&quot;}, initParams= {
        @WebInitParam(name=&quot;admin&quot;,value=&quot;Alan&quot;),    
        @WebInitParam(name=&quot;email&quot;,value=&quot;admin@example.com&quot;),    
    })
public class ServletDemo02 implements Servlet{

    @Override
    public void service(ServletRequest req, ServletResponse res) throws ServletException, IOException {
        String name=getServletConfig().getInitParameter(&quot;admin&quot;);
        String email=getServletConfig().getInitParameter(&quot;email&quot;);
        res.getWriter().print(&quot;name: &quot;+name);
        res.getWriter().print(&quot; email: &quot;+email);

    }

    @Override
    public void destroy() {
    }

    @Override
    public ServletConfig getServletConfig() {

        return null;
    }
    @Override
    public String getServletInfo() {

        return null;
    }
    @Override
    public void init(ServletConfig config) throws ServletException {
    }
}
