思路：找到目标数字的每一位数字与之后输入的数相等的数字个数，求出PA ，同理得到PB ，两次求和。

#include &lt;iostream&gt;
#include&lt;vector&gt;
#include&lt;cstdio&gt;

using namespace std;

int main()
{
    int a,b,c,d,sum1=0,sum2=0,muti1=1,muti2=1;
    cin&gt;&gt;a&gt;&gt;b&gt;&gt;c&gt;&gt;d;
    vector&lt;int&gt; v1,v2;
    while(a&gt;1)
    {
        int temp=a%10;
        v1.push_back(temp);
        a/=10;
    }
    for(int i=0;i&lt;v1.size();i++)
    {
        if(v1[i]==b)
        {
            v1[i]=v1[i]*muti1;
            sum1+=v1[i];
            muti1*=10;
        }
    }
    while(c&gt;1)
    {
        int temp=c%10;
        v2.push_back(temp);
        c/=10;
    }
    for(int i=0;i&lt;v2.size();i++)
    {
        if(v2[i]==d)
        {
            v2[i]=v2[i]*muti2;
            sum2+=v2[i];
            muti2*=10;
        }
    }
